function toPatientFromBackend(raw: any): Patient {
  const firstName = raw.firstName || "";
  const lastName = raw.lastName || "";
  const fullName = `${firstName} ${lastName}`.trim() || raw.name || "Unnamed Patient";
  const genderRaw = String(raw.gender || "").toUpperCase();
  const gender: Patient["gender"] = genderRaw === "FEMALE" ? "Female" : "Male";
  const latestVisitStatus = raw?.visits?.[0]?.status
    ? String(raw.visits[0].status)
    : "";
  const moduleMatch = latestVisitStatus.match(/^MODULE_(\d+)$/i);
  const queueModuleId = moduleMatch ? Number(moduleMatch[1]) : undefined;
  const queueFromModule: Record<number, Patient["queueStatus"]> = {
    3: "TRIAGE",
    36: "CONSULTATION",
    8: "LAB",
    10: "PHARMACY",
    13: "BILLING",
    1: "WAITING",
  };
  const queueRaw = String(
    raw.queueStatus ||
      raw.status ||
      (queueModuleId ? queueFromModule[queueModuleId] || "WAITING" : "") ||
      latestVisitStatus ||
      "WAITING",
  ).toUpperCase();
  const allowed: Patient["queueStatus"][] = [
    "WAITING",
    "TRIAGE",
    "CONSULTATION",
    "LAB",
    "PHARMACY",
    "BILLING",
    "COMPLETED",
  ];
  const queueStatus = (allowed.includes(queueRaw as any)
    ? queueRaw
    : "WAITING") as Patient["queueStatus"];
  return {
    id: String(raw.id),
    regNo: raw.patientCode || raw.regNo || "",
    nationalId: raw.nationalId || "",
    name: fullName,
    phone: raw.phone || "",
    gender,
    age: Number(raw.age || 0),
    queueStatus,
    queueModuleId:
      typeof raw.queueModuleId === "number"
        ? raw.queueModuleId
        : queueModuleId,
    visitDate: String(raw.visitDate || raw.createdAt || new Date().toISOString()).slice(0, 10),
    vitals: raw.vitals
      ? {
          bp: raw.vitals.bp || "",
          temp: raw.vitals.temp || "",
          weight: raw.vitals.weight || "",
          pulse: raw.vitals.pulse || "",
        }
      : undefined,
  };
}

const QUEUE_FIELD_KEYS = [
  "queue_to_next_module",
  "next_queue_route",
  "next_route",
  "queue_route",
];

function isQueueField(fieldKey: string) {
  return QUEUE_FIELD_KEYS.includes(fieldKey);
}

const BACKEND_GENERATED_FIELD_KEYS = new Set([
  "patientid",
  "visitid",
  "queuetoken",
  "opdtoken",
  "tokennumber",
  "inpatientid",
  "admissionid",
  "billid",
  "invoiceid",
]);

function normalizeFieldKey(fieldKey: string) {
  return String(fieldKey || "")
    .toLowerCase()
    .replace(/[^a-z0-9]/g, "");
}

function isBackendGeneratedField(fieldKey: string) {
  return BACKEND_GENERATED_FIELD_KEYS.has(normalizeFieldKey(fieldKey));
}

function readNestedValue(source: any, path: string) {
  const parts = String(path || "")
    .split(".")
    .filter(Boolean);
  let current = source;
  for (const part of parts) {
    if (!current || typeof current !== "object") return undefined;
    current = current[part];
  }
  return current;
}

function firstNonEmptyString(...values: unknown[]) {
  for (const value of values) {
    const text = String(value ?? "").trim();
    if (text) return text;
  }
  return "";
}

function extractGeneratedFieldValuesFromResult(
  result: any,
  selectedPatientId?: string,
): Record<string, string> {
  const visitId = firstNonEmptyString(
    readNestedValue(result, "visit.id"),
    readNestedValue(result, "outpatient.visitId"),
    result?.visitId,
    result?.visit_id,
  );
  const queueToken = firstNonEmptyString(
    readNestedValue(result, "queue.tokenNumber"),
    readNestedValue(result, "token.tokenNumber"),
    result?.queueToken,
    result?.queue_token,
    result?.tokenNumber,
    result?.token_number,
  );
  const inpatientId = firstNonEmptyString(
    readNestedValue(result, "inpatient.id"),
    readNestedValue(result, "admission.id"),
    result?.inpatientId,
    result?.inpatient_id,
    result?.admissionId,
    result?.admission_id,
  );
  const patientId = firstNonEmptyString(
    result?._resolvedPatientId,
    readNestedValue(result, "patient.id"),
    result?.patientId,
    result?.patient_id,
    selectedPatientId,
  );
  const billId = firstNonEmptyString(
    readNestedValue(result, "bill.id"),
    result?.billId,
    result?.bill_id,
  );
  const invoiceId = firstNonEmptyString(
    readNestedValue(result, "invoice.id"),
    result?.invoiceId,
    result?.invoice_id,
  );

  const generated: Record<string, string> = {};
  if (patientId) {
    generated.patient_id = patientId;
    generated.patientId = patientId;
  }
  if (visitId) {
    generated.visit_id = visitId;
    generated.visitId = visitId;
  }
  if (queueToken) {
    generated.queue_token = queueToken;
    generated.opd_token = queueToken;
    generated.token_number = queueToken;
    generated.tokenNumber = queueToken;
  }
  if (inpatientId) {
    generated.inpatient_id = inpatientId;
    generated.inpatientId = inpatientId;
    generated.admission_id = inpatientId;
    generated.admissionId = inpatientId;
  }
  if (billId) {
    generated.bill_id = billId;
    generated.billId = billId;
  }
  if (invoiceId) {
    generated.invoice_id = invoiceId;
    generated.invoiceId = invoiceId;
  }
  return generated;
}

function normalizeQueueLabel(raw: string) {
  return raw
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

function withNoneQueueOption(options: string[]) {
  const merged = ["None", ...options];
  return Array.from(new Set(merged.map((option) => String(option || "").trim()).filter(Boolean)));
}

function normalizePersonName(value: string) {
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function namesLikelyMatch(a: string, b: string) {
  const left = normalizePersonName(a);
  const right = normalizePersonName(b);
  if (!left || !right) return false;
  if (left === right) return true;
  return left.includes(right) || right.includes(left);
}

function resolveQueueModuleId(rawValue: string) {
  const value = String(rawValue || "").trim();
  if (!value) return { isComplete: false, moduleId: undefined as number | undefined };
  if (/^none$/i.test(value)) {
    return { isComplete: false, moduleId: undefined as number | undefined, isNone: true };
  }
  if (/discharge|complete|completed|done/i.test(value)) {
    return { isComplete: true, moduleId: 1 };
  }
  const normalized = normalizeQueueLabel(value);
  const aliasMap: Array<[RegExp, number]> = [
    [/triage/, 36],
    [/\bopd\b|out patient|outpatient|doctor consultation|consultation|back to doctor/, 36],
    [/\blab\b|laboratory/, 8],
    [/radiology|imaging/, 9],
    [/pharmacy|dispens/, 10],
    [/billing|cashier|invoice|payment/, 13],
    [/in patient|inpatient|admit|ipd/, 2],
    [/appointment/, 4],
    [/telemedicine|virtual consultation|video consult/, 21],
    [/emergency|er\b|ed\b/, 25],
    [/maternity|obstetric|obgyn|antenatal|anc|labor|delivery|postnatal/, 37],
    [/cost accounting|department profitability|profitability|margin analysis/, 45],
    [/strategic planning|executive dashboard|executive|control tower/, 46],
    [/orchestration|event bus|event driven|data ownership|integration backbone/, 47],
    [/registration|register/, 1],
    [/queue management/, 28],
  ];
  const alias = aliasMap.find(([pattern]) => pattern.test(normalized));
  if (alias) return { isComplete: false, moduleId: alias[1] };
  const exact = WORKFLOW_MODULES.find((m) => normalizeQueueLabel(m.name) === normalized);
  if (exact) return { isComplete: false, moduleId: exact.id };
  const contains = WORKFLOW_MODULES.find((m) => {
    const moduleLabel = normalizeQueueLabel(m.name);
    return moduleLabel.includes(normalized) || normalized.includes(moduleLabel);
  });
  if (contains) return { isComplete: false, moduleId: contains.id };
  return { isComplete: false, moduleId: undefined as number | undefined };
}

