function loadRegistrationSnapshots(): Record<string, Record<string, string>> {
  const raw = localStorage.getItem(REGISTRATION_SNAPSHOT_STORAGE_KEY);
  if (!raw) return {};
  try {
    return JSON.parse(raw);
  } catch {
    return {};
  }
}

function saveRegistrationSnapshot(patientId: string, data: Record<string, string>) {
  if (!patientId) return;
  const all = loadRegistrationSnapshots();
  all[patientId] = data;
  localStorage.setItem(REGISTRATION_SNAPSHOT_STORAGE_KEY, JSON.stringify(all));
}

function loadRegistrationSnapshot(
  patientId: string,
  fields: WorkflowField[],
): Record<string, string> {
  if (!patientId) return {};
  const all = loadRegistrationSnapshots();
  const snapshot = all[patientId];
  if (!snapshot) return {};
  const allowed = new Set(fields.map((field) => field.key));
  return Object.entries(snapshot).reduce<Record<string, string>>((acc, [key, value]) => {
    if (!allowed.has(key)) return acc;
    if (typeof value !== "string") return acc;
    acc[key] = value;
    return acc;
  }, {});
}

function emptyForm(fields: WorkflowField[]) {
  return fields.reduce<Record<string, string>>((acc, field) => {
    if (field.key === "registration_type") {
      acc[field.key] = "NEW";
      return acc;
    }
    if (field.key === "consent_version") {
      acc[field.key] = "v1";
      return acc;
    }
    acc[field.key] = "";
    return acc;
  }, {});
}

function loadWardCache(): any[] {
  const raw = localStorage.getItem(WARD_CACHE_STORAGE_KEY);
  if (!raw) return [];
  try {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

function saveWardCache(wards: any[]) {
  localStorage.setItem(WARD_CACHE_STORAGE_KEY, JSON.stringify(Array.isArray(wards) ? wards : []));
}

function toIsoDateFromAge(age: number) {
  if (!Number.isFinite(age) || age <= 0) return "";
  const now = new Date();
  const year = now.getFullYear() - Math.floor(age);
  return `${year}-${String(now.getMonth() + 1).padStart(2, "0")}-${String(
    now.getDate(),
  ).padStart(2, "0")}`;
}

function prefillFromPatient(patient: Patient, fields: WorkflowField[]) {
  const nameParts = patient.name.trim().split(/\s+/);
  const firstName = nameParts[0] || "";
  const lastName = nameParts.slice(1).join(" ");
  const genderUpper = patient.gender.toUpperCase();
  const dobGuess = toIsoDateFromAge(patient.age);

  const lookup: Record<string, string> = {
    full_name: patient.name || "",
    firstName,
    first_name: firstName,
    lastName,
    last_name: lastName,
    date_of_birth: dobGuess,
    dob: dobGuess,
    dateOfBirth: dobGuess,
    gender: genderUpper === "MALE" ? "Male" : genderUpper === "FEMALE" ? "Female" : patient.gender,
    registration_type: "RETURNING",
    national_id_passport: patient.nationalId || "",
    nationalId: patient.nationalId || "",
    phone: patient.phone || "",
    phone_number: patient.phone || "",
    patient_name: patient.name || "",
    patient_id: patient.id,
    patientId: patient.id,
    reg_no: patient.regNo || "",
    regNo: patient.regNo || "",
    patient_code: patient.regNo || "",
    patientCode: patient.regNo || "",
    search_reg_no: patient.regNo || "",
    search_id: patient.nationalId || "",
    search_national_id: patient.nationalId || "",
    search_phone: patient.phone || "",
    search_name: patient.name || "",
    age: String(patient.age || ""),
    queue_status: patient.queueStatus || "",
    visit_date: patient.visitDate || "",
    bp: patient.vitals?.bp || "",
    blood_pressure: patient.vitals?.bp || "",
    temperature: patient.vitals?.temp || "",
    temp: patient.vitals?.temp || "",
    weight: patient.vitals?.weight || "",
    pulse: patient.vitals?.pulse || "",
  };

  return fields.reduce<Record<string, string>>((acc, field) => {
    const value = lookup[field.key];
    if (typeof value === "string" && value.length > 0) {
      acc[field.key] = value;
    }
    return acc;
  }, {});
}

function prefillFromOtherModules(
  patientId: string,
  currentModuleId: number,
  fields: WorkflowField[],
) {
  const wantedKeys = new Set(fields.map((field) => field.key));
  const latestByKey: Record<string, { value: string; timestamp: number }> = {};

  for (const wfModule of WORKFLOW_MODULES) {
    if (wfModule.id === currentModuleId) continue;
    const key = `hmis_workflow_records_${wfModule.id}`;
    const raw = localStorage.getItem(key);
    if (!raw) continue;

    try {
      const rows = JSON.parse(raw) as Array<{
        patientId: string;
        updatedAt?: string;
        createdAt?: string;
        data?: Record<string, string>;
      }>;
      rows
        .filter((row) => row.patientId === patientId && row.data)
        .forEach((row) => {
          const ts = Date.parse(row.updatedAt || row.createdAt || "");
          const timestamp = Number.isFinite(ts) ? ts : 0;
          Object.entries(row.data || {}).forEach(([k, v]) => {
            if (!wantedKeys.has(k)) return;
            if (typeof v !== "string" || v.length === 0) return;
            const previous = latestByKey[k];
            if (!previous || timestamp >= previous.timestamp) {
              latestByKey[k] = { value: v, timestamp };
            }
          });
        });
    } catch {
      // ignore malformed local record payloads
    }
  }

  return Object.entries(latestByKey).reduce<Record<string, string>>((acc, [key, value]) => {
    acc[key] = value.value;
    return acc;
  }, {});
}

function prefillFromModuleRecords(
  patientId: string,
  moduleId: number,
  fields: WorkflowField[],
  includeEmpty = false,
) {
  const wantedKeys = new Set(fields.map((field) => field.key));
  const storageKey = `hmis_workflow_records_${moduleId}`;
  const raw = localStorage.getItem(storageKey);
  if (!raw) return {} as Record<string, string>;

  try {
    const rows = JSON.parse(raw) as Array<{
      patientId: string;
      updatedAt?: string;
      createdAt?: string;
      data?: Record<string, string>;
    }>;
    const latest = rows
      .filter((row) => row.patientId === patientId && row.data)
      .sort((a, b) => {
        const at = Date.parse(a.updatedAt || a.createdAt || "");
        const bt = Date.parse(b.updatedAt || b.createdAt || "");
        return (Number.isFinite(bt) ? bt : 0) - (Number.isFinite(at) ? at : 0);
      })[0];
    if (!latest?.data) return {} as Record<string, string>;

    return Object.entries(latest.data).reduce<Record<string, string>>((acc, [key, value]) => {
      if (!wantedKeys.has(key)) return acc;
      if (typeof value !== "string") return acc;
      if (!includeEmpty && value === "") return acc;
      acc[key] = value;
      return acc;
    }, {});
  } catch {
    return {} as Record<string, string>;
  }
}

function prefillFromPatientDetails(
  details: any,
  fields: WorkflowField[],
  includeEmpty = false,
) {
  const payload =
    (details && typeof details === "object" && (details.data || details.patient || details.item)) ||
    details ||
    {};

  const normalizeKey = (value: string) =>
    String(value || "")
      .toLowerCase()
      .replace(/[^a-z0-9]/g, "");

  const toFlatString = (value: unknown) => {
    if (value === null || value === undefined) return "";
    if (Array.isArray(value)) {
      return value
        .map((item) => {
          if (item === null || item === undefined) return "";
          if (typeof item === "object") return "";
          return String(item).trim();
        })
        .filter(Boolean)
        .join(", ");
    }
    if (typeof value === "object") return "";
    return String(value).trim();
  };

  const flattenedLookup: Record<string, string> = {};
  const pushLookup = (rawKey: string, rawValue: unknown) => {
    const key = normalizeKey(rawKey);
    const value = toFlatString(rawValue);
    if (!key) return;
    if (!includeEmpty && value === "") return;
    if (value === "" && flattenedLookup[key] !== undefined) return;
    flattenedLookup[key] = value;
  };

  const walk = (node: any, parent = "", depth = 0) => {
    if (!node || depth > 3) return;
    if (Array.isArray(node)) {
      if (parent) pushLookup(parent, node);
      return;
    }
    if (typeof node !== "object") {
      if (parent) pushLookup(parent, node);
      return;
    }
    Object.entries(node).forEach(([k, v]) => {
      const path = parent ? `${parent}_${k}` : k;
      if (v && typeof v === "object" && !Array.isArray(v)) {
        walk(v, path, depth + 1);
        return;
      }
      pushLookup(k, v);
      pushLookup(path, v);
    });
  };
  walk(payload);

  const firstName = payload?.firstName || "";
  const lastName = payload?.lastName || "";
  const fullName = `${firstName} ${lastName}`.trim();
  const dob = payload?.dateOfBirth ? String(payload.dateOfBirth).slice(0, 10) : "";
  const latestVisitId = firstNonEmptyString(
    payload?.visitId,
    payload?.lastVisitId,
    payload?.latestVisitId,
    Array.isArray(payload?.visits) ? payload?.visits?.[0]?.id : "",
  );
  const latestQueueToken = firstNonEmptyString(
    payload?.queueToken,
    payload?.opdToken,
    payload?.tokenNumber,
    payload?.queue?.tokenNumber,
    payload?.token?.tokenNumber,
  );
  const latestAdmissionId = firstNonEmptyString(
    payload?.admissionId,
    payload?.inpatientId,
    payload?.currentAdmissionId,
  );
  const latestBillId = firstNonEmptyString(payload?.billId, payload?.currentBillId);
  const latestInvoiceId = firstNonEmptyString(payload?.invoiceId, payload?.currentInvoiceId);
  const genderRaw = String(payload?.gender || "").toUpperCase();
  const gender =
    genderRaw === "MALE" ? "Male" : genderRaw === "FEMALE" ? "Female" : payload?.gender || "";

  const mapping: Record<string, string> = {
    full_name: fullName,
    first_name: firstName,
    firstName,
    last_name: lastName,
    lastName,
    date_of_birth: dob,
    dateOfBirth: dob,
    dob,
    gender,
    national_id_passport: payload?.nationalId || "",
    nationalId: payload?.nationalId || "",
    phone: payload?.phone || "",
    email: payload?.email || "",
    physical_address: payload?.address || "",
    address: payload?.address || "",
    blood_group: payload?.bloodGroup || "",
    allergies: payload?.allergies || "",
    emergency_contact_name: payload?.nextOfKinName || "",
    emergency_contact_phone: payload?.nextOfKinPhone || "",
    insurance_provider: payload?.insuranceProvider || "",
    insurance_member_id: payload?.insuranceNumber || "",
    chronic_conditions: Array.isArray(payload?.chronicConditions)
      ? payload.chronicConditions.join(", ")
      : payload?.chronicConditions || "",
    current_medications: Array.isArray(payload?.currentMedications)
      ? payload.currentMedications.join(", ")
      : payload?.currentMedications || "",
    past_medical_history: payload?.pastHistory || payload?.pastMedicalHistory || "",
    surgeries: Array.isArray(payload?.surgeries)
      ? payload.surgeries.join(", ")
      : payload?.surgeries || "",
    preferred_hospital:
      payload?.preferredHospitalName || payload?.preferredHospitalId || "",
    assigned_primary_physician:
      payload?.primaryPhysicianName || payload?.primaryPhysicianId || "",
    emergency_contact_relationship: payload?.emergencyContactRelationship || "",
    registration_type: payload?.registrationType || "",
    referral_source: payload?.referralSource || "",
    duplicate_override_reason: payload?.duplicateOverrideReason || "",
    facility_link_note: payload?.facilityLinkNote || "",
    insurance_coverage_type: payload?.insuranceCoverageType || "",
    insurance_expiry: payload?.insuranceExpiry ? String(payload.insuranceExpiry).slice(0, 10) : "",
    insurance_copay_percent:
      payload?.insuranceCopayPercent === undefined || payload?.insuranceCopayPercent === null
        ? ""
        : String(payload.insuranceCopayPercent),
    employer: payload?.employer || "",
    marital_status: payload?.maritalStatus || "",
    occupation: payload?.occupation || "",
    county: payload?.county || "",
    consent_treatment:
      payload?.consentTreatment === undefined || payload?.consentTreatment === null
        ? ""
        : payload?.consentTreatment
          ? "true"
          : "false",
    consent_version: payload?.consentVersion || "",
    consent_accepted_at: payload?.consentAcceptedAt
      ? String(payload.consentAcceptedAt).slice(0, 10)
      : "",
    portal_access_enabled:
      payload?.portalAccessEnabled === undefined || payload?.portalAccessEnabled === null
        ? ""
        : payload?.portalAccessEnabled
          ? "true"
          : "false",
    search_reg_no: payload?.patientCode || payload?.regNo || "",
    search_id: payload?.nationalId || "",
    search_national_id: payload?.nationalId || "",
    search_phone: payload?.phone || "",
    search_name: fullName || payload?.name || "",
    patient_name: fullName || payload?.name || "",
    patient_code: payload?.patientCode || payload?.regNo || "",
    reg_no: payload?.patientCode || payload?.regNo || "",
    patient_id: payload?.id ? String(payload.id) : "",
    visit_id: latestVisitId,
    visitId: latestVisitId,
    queue_token: latestQueueToken,
    opd_token: latestQueueToken,
    token_number: latestQueueToken,
    tokenNumber: latestQueueToken,
    admission_id: latestAdmissionId,
    admissionId: latestAdmissionId,
    inpatient_id: latestAdmissionId,
    inpatientId: latestAdmissionId,
    bill_id: latestBillId,
    billId: latestBillId,
    invoice_id: latestInvoiceId,
    invoiceId: latestInvoiceId,
    preferred_hospital_id: payload?.preferredHospitalId || "",
    primary_physician_id: payload?.primaryPhysicianId || "",
    consultation_fee_paid:
      payload?.consultationFeePaid === undefined || payload?.consultationFeePaid === null
        ? ""
        : payload?.consultationFeePaid
          ? "True"
          : "False",
    consent_data_sharing:
      payload?.consentDataSharing === undefined || payload?.consentDataSharing === null
        ? ""
        : payload?.consentDataSharing
          ? "true"
          : "false",
    consent_marketing:
      payload?.consentMarketing === undefined || payload?.consentMarketing === null
        ? ""
        : payload?.consentMarketing
          ? "true"
          : "false",
  };

  const normalizedMapping = Object.entries(mapping).reduce<Record<string, string>>((acc, [k, v]) => {
    acc[normalizeKey(k)] = typeof v === "string" ? v : toFlatString(v);
    return acc;
  }, {});

  const aliases: Record<string, string[]> = {
    patientfromward: ["fullname", "name", "patientname"],
    patientpick: ["fullname", "name", "patientname"],
    patientselection: ["fullname", "name", "patientname"],
    searchregno: ["patientcode", "regno"],
    searchnationalid: ["nationalid"],
    searchid: ["nationalid"],
    searchphone: ["phone"],
    searchname: ["fullname", "name", "patientname"],
    nextofkinname: ["nextofkinname", "emergencycontactname"],
    nextofkinphone: ["nextofkinphone", "emergencycontactphone"],
    insurancememberid: ["insurancenumber"],
    insuranceprovider: ["insuranceprovider"],
  };

  return fields.reduce<Record<string, string>>((acc, field) => {
    const normalizedFieldKey = normalizeKey(field.key);
    const direct =
      mapping[field.key] ??
      normalizedMapping[normalizedFieldKey] ??
      flattenedLookup[normalizedFieldKey];
    const aliasValue =
      aliases[normalizedFieldKey]
        ?.map((alias) => normalizedMapping[normalizeKey(alias)] || flattenedLookup[normalizeKey(alias)])
        .find((v) => typeof v === "string" && (includeEmpty || v !== "")) || "";
    const value = (typeof direct === "string" && (includeEmpty || direct !== "")) ? direct : aliasValue;
    if (!includeEmpty && value === "") return acc;
    if (value === undefined) return acc;
    acc[field.key] = String(value);
    return acc;
  }, {});
}

type AmbulanceMapPoint = {
  id: string;
  label: string;
  status: string;
  lat: number;
  lng: number;
  popup: string;
};

const LEAFLET_CSS_ID = "hmis-leaflet-css";
const LEAFLET_JS_ID = "hmis-leaflet-js";
let leafletLoaderPromise: Promise<any> | null = null;

function ensureLeafletLoaded(): Promise<any> {
  if (typeof window === "undefined") {
    return Promise.reject(new Error("Leaflet is only available in browser context."));
  }
  const globalWindow = window as any;
  if (globalWindow.L) return Promise.resolve(globalWindow.L);
  if (leafletLoaderPromise) return leafletLoaderPromise;

  leafletLoaderPromise = new Promise((resolve, reject) => {
    const head = document.head || document.getElementsByTagName("head")[0];
    if (!head) {
      reject(new Error("Document head unavailable."));
      return;
    }

    if (!document.getElementById(LEAFLET_CSS_ID)) {
      const link = document.createElement("link");
      link.id = LEAFLET_CSS_ID;
      link.rel = "stylesheet";
      link.href = "https://unpkg.com/leaflet@1.9.4/dist/leaflet.css";
      head.appendChild(link);
    }

    const existingScript = document.getElementById(LEAFLET_JS_ID) as HTMLScriptElement | null;
    if (existingScript) {
      existingScript.addEventListener("load", () => resolve((window as any).L));
      existingScript.addEventListener("error", () =>
        reject(new Error("Failed to load Leaflet script.")),
      );
      return;
    }

    const script = document.createElement("script");
    script.id = LEAFLET_JS_ID;
    script.src = "https://unpkg.com/leaflet@1.9.4/dist/leaflet.js";
    script.async = true;
    script.onload = () => resolve((window as any).L);
    script.onerror = () => reject(new Error("Failed to load Leaflet script."));
    head.appendChild(script);
  });

  return leafletLoaderPromise;
}

function toFiniteNumber(value: unknown): number | null {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function haversineKm(
  fromLat: number,
  fromLng: number,
  toLat: number,
  toLng: number,
): number {
  const r = 6371;
  const toRad = (deg: number) => (deg * Math.PI) / 180;
  const dLat = toRad(toLat - fromLat);
  const dLng = toRad(toLng - fromLng);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(fromLat)) *
      Math.cos(toRad(toLat)) *
      Math.sin(dLng / 2) *
      Math.sin(dLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return r * c;
}

function dispatchStatusColorHex(statusRaw: string) {
  const status = String(statusRaw || "").toUpperCase();
  const colorMap: Record<string, string> = {
    REQUESTED: "#64748b",
    ASSIGNED: "#0284c7",
    DISPATCHED: "#0ea5e9",
    ARRIVED_SCENE: "#22c55e",
    TRANSPORTING: "#f59e0b",
    ARRIVED_HOSPITAL: "#10b981",
    COMPLETED: "#2563eb",
    CLOSED: "#475569",
    CANCELLED: "#dc2626",
  };
  return colorMap[status] || "#64748b";
}

function getNextDispatchStatuses(statusRaw: string): DispatchStatus[] {
  const status = String(statusRaw || "").toUpperCase();
  switch (status) {
    case "REQUESTED":
      return ["ASSIGNED", "CANCELLED"];
    case "ASSIGNED":
      return ["DISPATCHED", "CANCELLED"];
    case "DISPATCHED":
      return ["ARRIVED_SCENE", "CANCELLED"];
    case "ARRIVED_SCENE":
      return ["TRANSPORTING", "CANCELLED"];
    case "TRANSPORTING":
      return ["ARRIVED_HOSPITAL", "CANCELLED"];
    case "ARRIVED_HOSPITAL":
      return ["COMPLETED", "CANCELLED"];
    case "COMPLETED":
      return ["CLOSED"];
    default:
      return [];
  }
}

function getSlaTargetMinutes(priorityRaw: string): number {
  const priority = String(priorityRaw || "HIGH").toUpperCase();
  const byPriority: Record<string, number> = {
    CRITICAL: 10,
    HIGH: 15,
    MEDIUM: 25,
    LOW: 40,
  };
  return byPriority[priority] ?? 20;
}

function toDispatchStatusClassName(statusRaw: string): string {
  return String(statusRaw || "REQUESTED").toLowerCase().replace(/[^a-z0-9]+/g, "-");
}

function safeMapLabel(value: string): string {
  return String(value || "").replace(/[<>]/g, "");
}

function AmbulanceLeafletBoardMap({
  points,
  center,
  selectedDispatchId,
  onSelectDispatch,
}: {
  points: AmbulanceMapPoint[];
  center: { lat: number; lng: number };
  selectedDispatchId?: string;
  onSelectDispatch?: (dispatchId: string) => void;
}) {
  const mapContainerRef = useRef<HTMLDivElement | null>(null);
  const mapRef = useRef<any>(null);
  const markerLayerRef = useRef<any>(null);
  const [mapError, setMapError] = useState("");

  useEffect(() => {
    let cancelled = false;

    const renderMap = async () => {
      try {
        const L = await ensureLeafletLoaded();
        if (cancelled || !mapContainerRef.current) return;

        if (!mapRef.current) {
          const map = L.map(mapContainerRef.current, {
            zoomControl: true,
            attributionControl: true,
          }).setView([center.lat, center.lng], 11);
          L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
            maxZoom: 19,
            attribution: "&copy; OpenStreetMap contributors",
          }).addTo(map);
          markerLayerRef.current = L.layerGroup().addTo(map);
          mapRef.current = map;
        }

        const map = mapRef.current;
        const markerLayer = markerLayerRef.current;
        markerLayer?.clearLayers();

        const bounds: Array<[number, number]> = [];
        points.forEach((point) => {
          if (!Number.isFinite(point.lat) || !Number.isFinite(point.lng)) return;
          const isSelected = selectedDispatchId && point.id === selectedDispatchId;
          const marker = L.circleMarker([point.lat, point.lng], {
            radius: isSelected ? 10 : 8,
            color: dispatchStatusColorHex(point.status),
            weight: isSelected ? 3 : 2,
            fillColor: dispatchStatusColorHex(point.status),
            fillOpacity: 0.82,
          });
          marker.bindPopup(
            `<strong>${safeMapLabel(point.label)}</strong><br/>${safeMapLabel(point.popup)}`,
          );
          marker.on("click", () => onSelectDispatch?.(point.id));
          marker.addTo(markerLayer);
          bounds.push([point.lat, point.lng]);
        });

        if (bounds.length > 0) {
          map.fitBounds(bounds, { padding: [24, 24], maxZoom: 13 });
        } else {
          map.setView([center.lat, center.lng], 10);
        }

        setTimeout(() => map.invalidateSize(), 100);
        setMapError("");
      } catch {
        if (!cancelled) {
          setMapError(
            "Live map unavailable. Check internet access to load free Leaflet/OpenStreetMap tiles.",
          );
        }
      }
    };

    void renderMap();
    return () => {
      cancelled = true;
    };
  }, [points, center.lat, center.lng, selectedDispatchId, onSelectDispatch]);

  useEffect(() => {
    return () => {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
        markerLayerRef.current = null;
      }
    };
  }, []);

  if (mapError) {
    return <div className="ambulance-map-fallback">{mapError}</div>;
  }

  return <div ref={mapContainerRef} className="ambulance-leaflet-map" />;
}

