  useEffect(() => {
    let cancelled = false;
    if (module.id !== 7) {
      setNurseOptions([]);
      return;
    }

    const loadNurses = async () => {
      try {
        const rows = await fetchStaff();
        if (cancelled) return;
        const parsed = rows
          .map((row: any) => {
            const first = String(row?.firstName || "").trim();
            const last = String(row?.lastName || "").trim();
            const fullName = `${first} ${last}`.trim() || String(row?.name || "").trim();
            const roleText = Array.isArray(row?.assignments)
              ? row.assignments
                  .map((assignment: any) => String(assignment?.roleTitle || ""))
                  .join(" ")
              : "";
            return {
              name: fullName,
              roleText: roleText.toLowerCase(),
            };
          })
          .filter((row: { name: string; roleText: string }) => row.name.length > 0);

        const taggedNurses = parsed
          .filter((row: { name: string; roleText: string }) => row.roleText.includes("nurse"))
          .map((row: { name: string }) => row.name);
        const fallback = parsed.map((row: { name: string }) => row.name);
        const chosen = taggedNurses.length > 0 ? taggedNurses : fallback;
        setNurseOptions(Array.from(new Set(chosen)).sort((a, b) => a.localeCompare(b)));
      } catch {
        if (!cancelled) {
          setNurseOptions([]);
        }
      }
    };

    void loadNurses();
    return () => {
      cancelled = true;
    };
  }, [module.id]);

  const loadInpatientControlCenter = useCallback(async () => {
    if (!isInpatientModule) return;
    setIpdLoading(true);
    setIpdError("");
    try {
      const [dashboardRes, admissionsRes] = await Promise.allSettled([
        fetchInpatientDashboard(),
        fetchInpatientAdmissions(),
      ]);

      let loaded = false;
      let nextDashboard: any | null = null;
      let nextAdmissions: any[] = [];

      if (dashboardRes.status === "fulfilled") {
        nextDashboard = (dashboardRes.value as any) || null;
        loaded = true;
        if (Array.isArray((nextDashboard as any)?.admissions)) {
          nextAdmissions = (nextDashboard as any).admissions;
        }
      }
      if (admissionsRes.status === "fulfilled" && Array.isArray(admissionsRes.value)) {
        nextAdmissions = admissionsRes.value;
        loaded = true;
      }

      if (!loaded) {
        const errA =
          admissionsRes.status === "rejected" ? String(admissionsRes.reason?.message || "") : "";
        const errD =
          dashboardRes.status === "rejected" ? String(dashboardRes.reason?.message || "") : "";
        throw new Error(errA || errD || "Failed to load inpatient dashboard.");
      }

      setIpdDashboard(nextDashboard);
      setIpdAdmissions(Array.isArray(nextAdmissions) ? nextAdmissions : []);
    } catch (error: any) {
      setIpdError(String(error?.message || "Failed to load inpatient dashboard."));
    } finally {
      setIpdLoading(false);
    }
  }, [isInpatientModule]);

