  const handleBlockchainVerify = useCallback(
    async (e: React.FormEvent) => {
      e.preventDefault();
      if (!isBlockchainModule) return;
      setBcError("");
      try {
        const hash = bcVerifyHashValue.trim();
        if (!hash && !bcVerifyEntityId.trim()) {
          throw new Error("Provide entity ID or hash value to verify.");
        }

        let payload: unknown = undefined;
        const payloadRaw = bcVerifyPayload.trim();
        if (payloadRaw) {
          try {
            payload = JSON.parse(payloadRaw);
          } catch {
            payload = { raw: payloadRaw };
          }
        }

        const result = hash
          ? await verifyBlockchainHash(hash)
          : await verifyBlockchainEntity({
              entityType: bcVerifyEntityType,
              entityId: bcVerifyEntityId.trim(),
              payload,
              entityHash: undefined,
            });
        setBcVerifyResult(result || null);
      } catch (error: any) {
        setBcError(String(error?.message || "Blockchain verification failed."));
      }
    },
    [
      isBlockchainModule,
      bcVerifyHashValue,
      bcVerifyEntityType,
      bcVerifyEntityId,
      bcVerifyPayload,
    ],
  );

