  const nearestAmbulanceSuggestion = useMemo(() => {
    if (!ambulanceDispatchTargetCoords) return null;
    const candidates = ambulanceFleet
      .filter((row: any) => String(row?.status || "").toUpperCase() === "AVAILABLE")
      .map((fleet: any) => {
        const fleetId = String(fleet?.id || "");
        const loc = ambulanceLatestLocationByFleet[fleetId];
        if (!loc) return null;
        const distanceKm = haversineKm(
          ambulanceDispatchTargetCoords.lat,
          ambulanceDispatchTargetCoords.lng,
          loc.lat,
          loc.lng,
        );
        return {
          fleetId,
          vehicleNumber: String(fleet?.vehicleNumber || fleetId),
          distanceKm,
          lastSeenAt: loc.capturedAt,
        };
      })
      .filter(Boolean) as Array<{
      fleetId: string;
      vehicleNumber: string;
      distanceKm: number;
      lastSeenAt: string;
    }>;
    if (candidates.length === 0) return null;
    return candidates.sort((a, b) => a.distanceKm - b.distanceKm)[0];
  }, [ambulanceDispatchTargetCoords, ambulanceFleet, ambulanceLatestLocationByFleet]);
