  const ambulanceSlaBreaches = useMemo(() => {
    const now = Date.now();
    return ambulanceDispatches
      .map((row: any) => {
        const status = String(row?.status || "REQUESTED").toUpperCase();
        if (["CLOSED", "CANCELLED"].includes(status)) return null;
        const meta = row?.meta || {};
        const priority = String(meta?.priority || "HIGH").toUpperCase();
        const targetMinutes = getSlaTargetMinutes(priority);
        const calledAtRaw = String(meta?.timestamps?.calledAt || row?.dispatchedAt || "");
        const calledAtMs = Date.parse(calledAtRaw);
        if (!Number.isFinite(calledAtMs)) return null;

        const arrivedSceneTransition = Array.isArray(row?.transitions)
          ? row.transitions.find(
              (transition: any) =>
                String(transition?.toStatus || "").toUpperCase() === "ARRIVED_SCENE",
            )
          : null;
        const arrivedAtRaw = String(
          meta?.timestamps?.arrivedSceneAt || arrivedSceneTransition?.changedAt || "",
        );
        const arrivedAtMs = Date.parse(arrivedAtRaw);

        let responseMinutes = 0;
        let mode: "LIVE" | "FINAL" = "LIVE";
        if (Number.isFinite(arrivedAtMs)) {
          responseMinutes = Math.max(0, Math.round((arrivedAtMs - calledAtMs) / 60000));
          mode = "FINAL";
        } else {
          if (!["REQUESTED", "ASSIGNED", "DISPATCHED"].includes(status)) return null;
          responseMinutes = Math.max(0, Math.round((now - calledAtMs) / 60000));
        }
        if (responseMinutes <= targetMinutes) return null;

        return {
          id: String(row?.id || ""),
          status,
          priority,
          patientName: String(meta?.patientName || "Unknown patient"),
          vehicleNumber: String(row?.fleet?.vehicleNumber || row?.fleetId || "-"),
          responseMinutes,
          targetMinutes,
          breachBy: responseMinutes - targetMinutes,
          mode,
        };
      })
      .filter(Boolean)
      .sort((a: any, b: any) => Number(b.breachBy || 0) - Number(a.breachBy || 0))
      .slice(0, 10) as Array<{
      id: string;
      status: string;
      priority: string;
      patientName: string;
      vehicleNumber: string;
      responseMinutes: number;
      targetMinutes: number;
      breachBy: number;
      mode: "LIVE" | "FINAL";
    }>;
  }, [ambulanceDispatches]);
