  const openPatientProfile = (patientId: string) => {
    const open = async () => {
      setDetailsLoading(true);
      try {
        if (module.id === 6) {
          const [detailsRes, summaryRes, timelineRes] = await Promise.allSettled([
            fetchTenantPatientById(patientId),
            fetchEmrPatientSummary(patientId),
            fetchEmrPatientTimeline(patientId),
          ]);
          setProfilePatientDetails(
            detailsRes.status === "fulfilled" ? detailsRes.value : null,
          );
          setEhrPatientSummary(
            summaryRes.status === "fulfilled" ? summaryRes.value : null,
          );
          const timelinePayload =
            timelineRes.status === "fulfilled"
              ? (timelineRes.value as any)?.timeline ?? []
              : [];
          setEhrPatientTimeline(Array.isArray(timelinePayload) ? timelinePayload : []);
        } else {
          const details = await fetchTenantPatientById(patientId);
          setProfilePatientDetails(details);
          setEhrPatientSummary(null);
          setEhrPatientTimeline([]);
        }
      } catch {
        setProfilePatientDetails(null);
        setEhrPatientSummary(null);
        setEhrPatientTimeline([]);
      } finally {
        setDetailsLoading(false);
      }
    };
    const patientFromList = patients.find((p) => p.id === patientId) || null;
    const patientFromEhr = ehrRows.find((row) => row.id === patientId);
    const patient =
      patientFromList ||
      (patientFromEhr
        ? ({
            id: patientFromEhr.id,
            name: patientFromEhr.fullName,
            regNo: patientFromEhr.patientCode,
            phone: patientFromEhr.phone,
            nationalId: "",
            gender:
              patientFromEhr.gender === "FEMALE"
                ? "Female"
                : patientFromEhr.gender === "OTHER"
                  ? "Other"
                  : "Male",
            age: 0,
            queueStatus: "WAITING",
            visitDate: patientFromEhr.lastVisitDate || patientFromEhr.registrationDate || "",
          } as Patient)
        : null);
    setProfilePatient(patient);
    void open();
  };

