  const handlePosCreateSale = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isPosModule) return;
    if (posCart.length === 0) {
      setFormNotice({ type: "error", message: "Add at least one item to POS cart." });
      return;
    }
    if (posSaleType === "PRESCRIPTION" && !posSelectedPatientId && !posPrescriptionId.trim()) {
      setFormNotice({
        type: "error",
        message: "Prescription sale requires patient or prescription ID.",
      });
      return;
    }
    if (posPaymentMethod === "MPESA" && !posMpesaPhone.trim() && !posWalkInPhone.trim()) {
      setFormNotice({
        type: "error",
        message: "M-Pesa phone number is required.",
      });
      return;
    }
    try {
      const splitPayments: Array<{ method: "MPESA" | "CASH" | "CARD" | "INSURANCE"; amount: number }> = [];
      const cashSplit = Number(posSplitCashAmount || 0);
      const cardSplit = Number(posSplitCardAmount || 0);
      const mpesaSplit = Number(posSplitMpesaAmount || 0);
      const insuranceSplit = Number(posSplitInsuranceAmount || 0);
      if (posPaymentMethod === "SPLIT") {
        if (cashSplit > 0) splitPayments.push({ method: "CASH", amount: cashSplit });
        if (cardSplit > 0) splitPayments.push({ method: "CARD", amount: cardSplit });
        if (mpesaSplit > 0) splitPayments.push({ method: "MPESA", amount: mpesaSplit });
        if (insuranceSplit > 0) splitPayments.push({ method: "INSURANCE", amount: insuranceSplit });
      }
      const splitTotal = splitPayments.reduce((sum, row) => sum + Number(row.amount || 0), 0);

      const payload: any = {
        patientId: posSelectedPatientId || undefined,
        prescriptionId: posPrescriptionId.trim() || undefined,
        saleType: posSaleType,
        items: posCart.map((item) => ({
          itemId: item.itemId,
          name: item.name,
          quantity: item.quantity,
          unitPrice: item.unitPrice,
          discountPercent: item.discountPercent,
          controlledSubstance: item.controlledSubstance,
        })),
        paymentMethod: posPaymentMethod,
        splitPayments: splitPayments.length ? splitPayments : undefined,
        paidAmount:
          posPaymentMethod === "SPLIT"
            ? splitTotal
            : Number.isFinite(Number(posPaidAmount))
              ? Number(posPaidAmount)
              : undefined,
        discountAmount: Number.isFinite(Number(posDiscountAmount))
          ? Number(posDiscountAmount)
          : undefined,
        discountPercent: Number.isFinite(Number(posDiscountPercent))
          ? Number(posDiscountPercent)
          : undefined,
        taxPercent: Number.isFinite(Number(posTaxPercent)) ? Number(posTaxPercent) : undefined,
        insuranceProvider: posInsuranceProvider.trim() || undefined,
        insuranceMemberId: posInsuranceMemberId.trim() || undefined,
        insuranceCoveragePercent: Number.isFinite(Number(posInsuranceCoveragePercent))
          ? Number(posInsuranceCoveragePercent)
          : undefined,
        coPayAmount: Number.isFinite(Number(posCoPayAmount)) ? Number(posCoPayAmount) : undefined,
        walkInCustomerName: posWalkInName.trim() || undefined,
        walkInCustomerPhone: posWalkInPhone.trim() || undefined,
        phoneNumber: posMpesaPhone.trim() || undefined,
        notes: posNotes.trim() || undefined,
      };

      const sale = await createPharmacyPosSale(payload);
      setFormNotice({
        type: "success",
        message: `POS sale saved successfully. Receipt ${sale?.receipt?.number || ""}`,
      });
      if (sale?.transactionId) {
        try {
          const receiptDetail = await fetchPharmacyPosReceipt(String(sale.transactionId));
          setPosReceiptDetail(receiptDetail || null);
        } catch {
          setPosReceiptDetail(null);
        }
      } else {
        setPosReceiptDetail(null);
      }
      setPosCart([]);
      setPosSelectedPatientId("");
      setPosSelectedPatientName("");
      setPosPatientSearch("");
      setPosPatientResults([]);
      setPosPrescriptionId("");
      setPosWalkInName("");
      setPosWalkInPhone("");
      setPosPaidAmount("");
      setPosDiscountAmount("");
      setPosDiscountPercent("0");
      setPosInsuranceProvider("");
      setPosInsuranceMemberId("");
      setPosInsuranceCoveragePercent("0");
      setPosCoPayAmount("");
      setPosMpesaPhone("");
      setPosSplitCashAmount("");
      setPosSplitCardAmount("");
      setPosSplitMpesaAmount("");
      setPosSplitInsuranceAmount("");
      setPosNotes("");
      await loadPharmacyPosControlCenter();
    } catch (error: any) {
      setFormNotice({
        type: "error",
        message: String(error?.message || "Failed to complete POS sale."),
      });
    }
  };

