  const handlePosPrintReceipt = () => {
    const detail = posReceiptDetail;
    if (!detail?.transaction) return;
    const win = window.open("", "_blank", "width=840,height=900");
    if (!win) return;
    const tx = detail.transaction;
    const receipt = detail.receipt || {};
    const items = Array.isArray(tx.items) ? tx.items : [];
    const rows = items
      .map(
        (item: any) =>
          `<tr><td>${item?.name || "-"}</td><td>${Number(item?.quantity || 0)}</td><td>${Number(
            item?.unitPrice || 0,
          ).toFixed(2)}</td><td>${Number(item?.lineTotal || 0).toFixed(2)}</td></tr>`,
      )
      .join("");
    win.document.write(`
      <html>
        <head>
          <title>POS Receipt ${receipt?.number || tx.id}</title>
          <style>
            body{font-family: Arial, sans-serif; padding:24px; color:#111;}
            h2,h3,p{margin:0 0 8px;}
            table{border-collapse:collapse; width:100%; margin-top:12px;}
            th,td{border:1px solid #ddd; padding:8px; text-align:left; font-size:13px;}
            .meta{margin-top:10px; font-size:13px;}
          </style>
        </head>
        <body>
          <h2>${detail?.facility?.name || "Facility"}</h2>
          <p>Receipt: ${receipt?.number || tx.id}</p>
          <p>Date: ${String(tx?.transactionDate || "").slice(0, 19).replace("T", " ")}</p>
          <p>Served By: ${tx?.servedBy?.name || "-"}</p>
          <p>Payment: ${tx?.paymentMethod || "-"}</p>
          <p>Status: ${tx?.status || "-"}</p>
          <div class="meta">Patient: ${tx?.patientName || "-"}</div>
          <table>
            <thead>
              <tr><th>Item</th><th>Qty</th><th>Unit Price</th><th>Line Total</th></tr>
            </thead>
            <tbody>${rows || "<tr><td colspan='4'>No items</td></tr>"}</tbody>
          </table>
	          <div class="meta">
	            <p>Gross: ${Number(tx?.totals?.grossAmount || tx?.amount || 0).toFixed(2)}</p>
	            <p>Tax: ${Number(tx?.totals?.taxAmount || 0).toFixed(2)}</p>
	            <p>Paid: ${Number(tx?.totals?.paidAmount || tx?.amount || 0).toFixed(2)}</p>
	            <p>Outstanding: ${Number(tx?.totals?.outstandingAmount || 0).toFixed(2)}</p>
	            <p>Bill ID: ${tx?.billing?.billId || "-"}</p>
	            <p>Bill Status: ${tx?.billing?.status || "-"}</p>
	            <p>Bill Outstanding: ${Number(tx?.billing?.outstandingAmount || 0).toFixed(2)}</p>
	          </div>
	        </body>
	      </html>
	    `);
    win.document.close();
    win.focus();
    win.print();
  };

  const handleMortuaryCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isMortuaryModule) return;
    if (!mortuaryDateOfDeath) {
      setFormNotice({ type: "error", message: "Date of death is required." });
      return;
    }
    if (mortuarySource === "INTERNAL" && !mortuarySelectedPatientId) {
      setFormNotice({ type: "error", message: "Select a patient for internal death registration." });
      return;
    }
    if (mortuarySource === "EXTERNAL" && !mortuaryDeceasedName.trim()) {
      setFormNotice({ type: "error", message: "Deceased full name is required for external intake." });
      return;
    }
    try {
      const created = await createMortuaryRecord({
        source: mortuarySource,
        patientId: mortuarySource === "INTERNAL" ? mortuarySelectedPatientId || undefined : undefined,
        deceasedName: mortuarySource === "EXTERNAL" ? mortuaryDeceasedName.trim() : undefined,
        dateOfDeath: mortuaryDateOfDeath,
        causeOfDeath: mortuaryCause.trim() || undefined,
        gender: mortuaryGender || undefined,
        age: Number.isFinite(Number(mortuaryAge)) ? Number(mortuaryAge) : undefined,
        nationalId: mortuaryNationalId.trim() || undefined,
        nextOfKinName: mortuaryNokName.trim() || undefined,
        nextOfKinPhone: mortuaryNokPhone.trim() || undefined,
        certifyingDoctor: mortuaryDoctor.trim() || undefined,
        policeCaseNumber: mortuaryPoliceCase.trim() || undefined,
        infectiousFlag: mortuaryInfectiousFlag,
        status: mortuaryStatus as any,
        storageUnit: mortuaryStorageUnit.trim() || undefined,
        storageRoom: mortuaryStorageRoom.trim() || undefined,
        storageRack: mortuaryStorageRack.trim() || undefined,
        storageTray: mortuaryStorageTray.trim() || undefined,
        policeHold: mortuaryPoliceHold,
        holdReason: mortuaryHoldReason.trim() || undefined,
        holdUntil: mortuaryHoldUntil || undefined,
        notes: mortuaryNotes.trim() || undefined,
      });
      setFormNotice({
        type: "success",
        message: `Mortuary record created: ${String(created?.mortuaryNumber || created?.id || "")}`,
      });
      setMortuaryAllocateRecordId(String(created?.id || ""));
      setMortuaryReleaseRecordId(String(created?.id || ""));
      setMortuaryDeceasedName("");
      setMortuaryCause("");
      setMortuaryGender("");
      setMortuaryAge("");
      setMortuaryNationalId("");
      setMortuaryNokName("");
      setMortuaryNokPhone("");
      setMortuaryDoctor("");
      setMortuaryPoliceCase("");
      setMortuaryInfectiousFlag(false);
      setMortuaryStorageUnit("");
      setMortuaryStorageRoom("");
      setMortuaryStorageRack("");
      setMortuaryStorageTray("");
      setMortuaryPoliceHold(false);
      setMortuaryHoldReason("");
      setMortuaryHoldUntil("");
      setMortuaryNotes("");
      setMortuaryPatientSearch("");
      setMortuaryPatientResults([]);
      if (mortuarySource === "EXTERNAL") {
        setMortuarySelectedPatientId("");
        setMortuarySelectedPatientName("");
      }
      await loadMortuaryControlCenter();
    } catch (error: any) {
      setFormNotice({
        type: "error",
        message: String(error?.message || "Failed to create mortuary record."),
      });
    }
  };

