  const handleInventoryReceiveMedicine = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isInventoryModule) return;
    const quantity = Number(invMedQuantity);
    const unitPrice = Number(invMedUnitPrice);
    if (!invMedName.trim() || !invMedBatchNumber.trim() || !invMedExpiryDate) {
      setFormNotice({
        type: "error",
        message: "Medicine name, batch number, and expiry date are required.",
      });
      return;
    }
    if (!invMedCategory.trim()) {
      setFormNotice({
        type: "error",
        message: "Medicine category is required.",
      });
      return;
    }
    if (!invMedVendor.trim()) {
      setFormNotice({
        type: "error",
        message: "Vendor is required for received stock.",
      });
      return;
    }
    if (!Number.isFinite(quantity) || quantity <= 0) {
      setFormNotice({
        type: "error",
        message: "Medicine quantity must be greater than zero.",
      });
      return;
    }
    if (!Number.isFinite(unitPrice) || unitPrice < 0) {
      setFormNotice({
        type: "error",
        message: "Unit price must be a valid non-negative number.",
      });
      return;
    }
    try {
      const normalizedVendor = invMedVendor.trim();
      const normalizedCategory = invMedCategory.trim();
      const receiveReason = `Restock batch ${invMedBatchNumber.trim()} | Vendor: ${normalizedVendor} | Category: ${normalizedCategory}`;
      const match = invMedicines.find(
        (medicine) =>
          String(medicine?.name || "").trim().toLowerCase() ===
            invMedName.trim().toLowerCase() &&
          String(medicine?.batchNumber || "").trim().toLowerCase() ===
            invMedBatchNumber.trim().toLowerCase(),
      );
      if (match?.id) {
        await receiveInventoryMedicine(
          String(match.id),
          quantity,
          receiveReason,
          {
            supplierName: normalizedVendor,
            category: normalizedCategory,
          },
        );
        await updateInventoryMedicine(String(match.id), {
          unitPrice,
          expiryDate: invMedExpiryDate,
          genericName: invMedGenericName.trim() || undefined,
        });
        setFormNotice({
          type: "success",
          message: "Medicine stock updated (quantity increased).",
        });
      } else {
        await createInventoryMedicine({
          name: invMedName.trim(),
          genericName: invMedGenericName.trim() || undefined,
          batchNumber: invMedBatchNumber.trim(),
          expiryDate: invMedExpiryDate,
          quantity,
          unitPrice,
          category: normalizedCategory,
          supplierName: normalizedVendor,
        });
        setFormNotice({
          type: "success",
          message: "Medicine stock received successfully.",
        });
      }
      setInvMedName("");
      setInvMedGenericName("");
      setInvMedCategory("");
      setInvMedVendor("");
      setInvMedBatchNumber("");
      setInvMedExpiryDate("");
      setInvMedQuantity("");
      setInvMedUnitPrice("");
      await loadInventoryControlCenter();
    } catch (error: any) {
      setFormNotice({
        type: "error",
        message: String(error?.message || "Failed to receive medicine stock."),
      });
    }
  };

