    const nps = feedbackDashboard?.nps || {};
    const sentiment = feedbackDashboard?.sentiment || {};
    const ticketSummary = feedbackDashboard?.ticketSummary || {};
    const complaintsByCategory = Object.entries(feedbackDashboard?.complaintsByCategory || {})
      .map(([category, count]) => ({ category, count: Number(count || 0) }))
